#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

const int MAXN = 100005;

int N, Q;
vector<int> adj[MAXN];
long long A[MAXN];

struct Query {
    long long S;
    int id;
};
vector<Query> queries[MAXN];

int parent_node[MAXN], depth[MAXN];
long long pref[MAXN];
int sz[MAXN], heavy[MAXN];
int tin[MAXN], tout[MAXN], node_at[MAXN];
int timer = 0;

vector<long long> C;
int BIT[MAXN];
int M;
int ans[MAXN];

// DFS to calculate depths, subtree sizes, and heavy children
void dfs1(int u, int p) {
    parent_node[u] = p;
    depth[u] = depth[p] + 1;
    pref[u] = pref[p] + A[u];
    sz[u] = 1;
    tin[u] = ++timer;
    node_at[timer] = u;
    C.push_back(pref[u]);

    for (int v : adj[u]) {
        if (v != p) {
            dfs1(v, u);
            sz[u] += sz[v];
            if (heavy[u] == 0 || sz[v] > sz[heavy[u]]) {
                heavy[u] = v;
            }
        }
    }
    tout[u] = timer;
}

// Fenwick tree operations
void add(int idx, int val) {
    for (; idx <= M; idx += idx & -idx) BIT[idx] = max(BIT[idx], val);
}

int query(int idx) {
    int res = 0;
    for (; idx > 0; idx -= idx & -idx) res = max(res, BIT[idx]);
    return res;
}

void clear(int idx) {
    for (; idx <= M; idx += idx & -idx) BIT[idx] = 0;
}

int get_idx(long long val) {
    // upper_bound gets first element > val. Subtracting begin() gives the 1-based index count
    return upper_bound(C.begin(), C.end(), val) - C.begin();
}

// DSU on Tree to process queries offline
void dfs2(int u, int p, bool keep) {
    for (int v : adj[u]) {
        if (v != p && v != heavy[u]) dfs2(v, u, false);
    }
    if (heavy[u]) {
        dfs2(heavy[u], u, true);
    }

    // Re-add light children's subtrees
    for (int v : adj[u]) {
        if (v != p && v != heavy[u]) {
            for (int t = tin[v]; t <= tout[v]; ++t) {
                int x = node_at[t];
                add(get_idx(pref[x]), depth[x]);
            }
        }
    }
    // Add current node
    add(get_idx(pref[u]), depth[u]);

    // Answer queries for the current node
    for (auto& q : queries[u]) {
        long long limit = q.S + pref[p];
        int idx = get_idx(limit);
        if (idx > 0) {
            int max_d = query(idx);
            if (max_d >= depth[u]) {
                ans[q.id] = max_d - depth[u] + 1;
            } else {
                ans[q.id] = 0;
            }
        } else {
            ans[q.id] = 0;
        }
    }

    // Erase contributions if it was a light child
    if (!keep) {
        for (int t = tin[u]; t <= tout[u]; ++t) {
            int x = node_at[t];
            clear(get_idx(pref[x]));
        }
    }
}

int main() {
    // Fast I/O
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    if (!(cin >> N)) return 0;
    for (int i = 0; i < N - 1; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    for (int i = 1; i <= N; ++i) {
        cin >> A[i];
    }
    cin >> Q;
    for (int i = 0; i < Q; ++i) {
        int x;
        long long s;
        cin >> x >> s;
        queries[x].push_back({s, i});
    }

    dfs1(1, 0);

    // Coordinate compress the prefix sums
    sort(C.begin(), C.end());
    C.erase(unique(C.begin(), C.end()), C.end());
    M = C.size();

    dfs2(1, 0, true);

    for (int i = 0; i < Q; ++i) {
        cout << ans[i] << "\n";
    }

    return 0;
}

