#include <stdio.h>
#include <stdlib.h>

#define MAXN 100005

// Graph Adjacency List Arrays
int head[MAXN], to_edge[MAXN * 2], next_edge[MAXN * 2];
int edge_cnt = 0;

void add_edge(int u, int v) {
    edge_cnt++;
    to_edge[edge_cnt] = v;
    next_edge[edge_cnt] = head[u];
    head[u] = edge_cnt;
}

// Queries Arrays
int q_head[MAXN], q_id[MAXN], q_next[MAXN];
long long q_S[MAXN];
int q_cnt = 0;

void add_query(int u, long long s, int id) {
    q_cnt++;
    q_S[q_cnt] = s;
    q_id[q_cnt] = id;
    q_next[q_cnt] = q_head[u];
    q_head[u] = q_cnt;
}

long long A[MAXN];
int parent_node[MAXN], depth[MAXN], sz[MAXN], heavy[MAXN];
long long pref[MAXN];
int tin[MAXN], tout[MAXN], node_at[MAXN];
int timer = 0;

// Coordinate Compression Arrays
long long C_arr[MAXN];
long long C[MAXN];
int C_size = 0;
int M = 0;

int BIT[MAXN];
int ans[MAXN];

int cmp(const void* a, const void* b) {
    long long diff = (*(long long*)a - *(long long*)b);
    return (diff > 0) - (diff < 0);
}

// DFS 1: Establish Tree properties
void dfs1(int u, int p) {
    parent_node[u] = p;
    depth[u] = depth[p] + 1;
    pref[u] = pref[p] + A[u];
    sz[u] = 1;
    timer++;
    tin[u] = timer;
    node_at[timer] = u;

    C_arr[C_size++] = pref[u];

    for (int e = head[u]; e != 0; e = next_edge[e]) {
        int v = to_edge[e];
        if (v != p) {
            dfs1(v, u);
            sz[u] += sz[v];
            if (heavy[u] == 0 || sz[v] > sz[heavy[u]]) {
                heavy[u] = v;
            }
        }
    }
    tout[u] = timer;
}

int get_idx(long long val) {
    int low = 0, high = M - 1, count = 0;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (C[mid] <= val) {
            count = mid + 1;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    return count;
}

void add(int idx, int val) {
    for (; idx <= M; idx += idx & -idx) {
        if (val > BIT[idx]) BIT[idx] = val;
    }
}

int query(int idx) {
    int res = 0;
    for (; idx > 0; idx -= idx & -idx) {
        if (BIT[idx] > res) res = BIT[idx];
    }
    return res;
}

void clear(int idx) {
    for (; idx <= M; idx += idx & -idx) BIT[idx] = 0;
}

// DFS 2: DSU on Trees (Sack Algorithm)
void dfs2(int u, int p, int keep) {
    for (int e = head[u]; e != 0; e = next_edge[e]) {
        int v = to_edge[e];
        if (v != p && v != heavy[u]) dfs2(v, u, 0);
    }

    if (heavy[u] != 0) dfs2(heavy[u], u, 1);

    for (int e = head[u]; e != 0; e = next_edge[e]) {
        int v = to_edge[e];
        if (v != p && v != heavy[u]) {
            for (int t = tin[v]; t <= tout[v]; t++) {
                int x = node_at[t];
                add(get_idx(pref[x]), depth[x]);
            }
        }
    }
    add(get_idx(pref[u]), depth[u]);

    for (int e = q_head[u]; e != 0; e = q_next[e]) {
        long long limit = q_S[e] + pref[p];
        int idx = get_idx(limit);
        if (idx > 0) {
            int max_d = query(idx);
            if (max_d >= depth[u]) {
                ans[q_id[e]] = max_d - depth[u] + 1;
            } else {
                ans[q_id[e]] = 0;
            }
        } else {
            ans[q_id[e]] = 0;
        }
    }

    if (!keep) {
        for (int t = tin[u]; t <= tout[u]; t++) {
            clear(get_idx(pref[node_at[t]]));
        }
    }
}

int main() {
    int N;
    if (scanf("%d", &N) != 1) return 0;

    for (int i = 0; i <= N; i++) {
        head[i] = q_head[i] = heavy[i] = BIT[i] = 0;
    }

    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        add_edge(u, v);
        add_edge(v, u);
    }

    for (int i = 1; i <= N; i++) {
        scanf("%lld", &A[i]);
    }

    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int x;
        long long s;
        scanf("%d %lld", &x, &s);
        add_query(x, s, i);
    }

    dfs1(1, 0);

    // Sort and unique the prefix array for Coordinate Compression
    qsort(C_arr, C_size, sizeof(long long), cmp);
    if (C_size > 0) {
        long long last = C_arr[0];
        C[M++] = last;
        for (int i = 1; i < C_size; i++) {
            if (C_arr[i] != last) {
                last = C_arr[i];
                C[M++] = last;
            }
        }
    }

    dfs2(1, 0, 1);

    for (int i = 0; i < Q; i++) {
        printf("%d\n", ans[i]);
    }

    return 0;
}

