public class Main {
    static class FastScanner {
        InputStream in;
        byte[] buffer = new byte[1024];
        int head = 0, tail = 0;

        public FastScanner(InputStream in) { this.in = in; }

        public int read() {
            if (head >= tail) {
                head = 0;
                try { tail = in.read(buffer, 0, buffer.length); } catch (Exception e) {}
                if (tail <= 0) return -1;
            }
            return buffer[head++];
        }

        public long nextLong() {
            int c = read();
            while (c <= 32) {
                if (c == -1) return -1;
                c = read();
            }
            long res = 0;
            while (c > 32) {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res;
        }

        public int nextInt() {
            return (int) nextLong();
        }
    }

