const fs = require('fs');

function solve() {
    // Read all input into a buffer for blazing fast I/O
    const buffer = fs.readFileSync(0);
    let offset = 0;

    function readInt() {
        while (offset < buffer.length && buffer[offset] <= 32) offset++;
        if (offset >= buffer.length) return null;
        let res = 0;
        while (offset < buffer.length && buffer[offset] > 32) {
            res = res * 10 + (buffer[offset] - 48);
            offset++;
        }
        return res;
    }

    let N = readInt();
    if (N === null) return;

    // Adjacency List for the Tree
    let head = new Int32Array(N + 1).fill(-1);
    let to = new Int32Array((N - 1) * 2);
    let next = new Int32Array((N - 1) * 2);
    let edgeCnt = 0;

    function addEdge(u, v) {
        to[edgeCnt] = v;
        next[edgeCnt] = head[u];
        head[u] = edgeCnt++;
    }

    for (let i = 0; i < N - 1; i++) {
        let u = readInt(), v = readInt();
        addEdge(u, v);
        addEdge(v, u);
    }

    let A = new Float64Array(N + 1);
    for (let i = 1; i <= N; i++) A[i] = readInt();

    // Arrays to hold tree properties
    let parent = new Int32Array(N + 1);
    let depth = new Int32Array(N + 1);
    let pref = new Float64Array(N + 1);
    let tin = new Int32Array(N + 1);
    let tout = new Int32Array(N + 1);
    let timer = 0;

    // --- ITERATIVE DFS (Prevents Stack Overflow) ---
    let stack = new Int32Array(N + 1);
    let edgePtr = new Int32Array(N + 1);
    for (let i = 1; i <= N; i++) edgePtr[i] = head[i];

    let top = 0;
    stack[++top] = 1;
    parent[1] = 0;
    depth[1] = 1;
    pref[1] = A[1];

    while (top > 0) {
        let u = stack[top];

        // First time entering this node
        if (edgePtr[u] === head[u]) {
            tin[u] = ++timer;
        }

        let e = edgePtr[u];
        let foundChild = false;

        while (e !== -1) {
            let v = to[e];
            e = next[e];
            edgePtr[u] = e; // Save progress for when we backtrack

            if (v !== parent[u]) {
                parent[v] = u;
                depth[v] = depth[u] + 1;
                pref[v] = pref[u] + A[v];
                stack[++top] = v;
                foundChild = true;
                break; // Dive deeper
            }
        }

        // If no more children to process, we are leaving the node
        if (!foundChild) {
            tout[u] = timer;
            top--;
        }
    }

    // Read Queries
    let Q = readInt();
    let qX = new Int32Array(Q);
    let qLimit = new Float64Array(Q);
    let qIndices = new Int32Array(Q);

    for (let i = 0; i < Q; i++) {
        let x = readInt();
        let s = readInt();
        qX[i] = x;
        qLimit[i] = s + pref[parent[x]]; // Transform budget into a prefix limit
        qIndices[i] = i;
    }

    // Sort queries by their limit (ascending)
    qIndices.sort((a, b) => {
        if (qLimit[a] < qLimit[b]) return -1;
        if (qLimit[a] > qLimit[b]) return 1;
        return 0;
    });

    // Create an array of nodes and sort them by their prefix sum (ascending)
    let nodes = new Int32Array(N);
    for (let i = 0; i < N; i++) nodes[i] = i + 1;

    nodes.sort((a, b) => {
        if (pref[a] < pref[b]) return -1;
        if (pref[a] > pref[b]) return 1;
        return 0;
    });

    // --- ITERATIVE SEGMENT TREE ---
    // Calculate size padded to the nearest power of 2 for safety
    let SZ = 1;
    while (SZ < N + 2) SZ <<= 1;
    let ST = new Int32Array(2 * SZ).fill(0);

    function updateTree(idx, val) {
        idx += SZ;
        if (val > ST[idx]) ST[idx] = val;
        for (idx >>= 1; idx > 0; idx >>= 1) {
            ST[idx] = Math.max(ST[idx << 1], ST[(idx << 1) | 1]);
        }
    }

    function queryMax(l, r) {
        let res = 0;
        l += SZ;
        r += SZ + 1;
        for (; l < r; l >>= 1, r >>= 1) {
            if (l & 1) res = Math.max(res, ST[l++]);
            if (r & 1) res = Math.max(res, ST[--r]);
        }
        return res;
    }

    // --- OFFLINE SWEEP-LINE PROCESS ---
    let ans = new Int32Array(Q);
    let nodePtr = 0;

    for (let i = 0; i < Q; i++) {
        let qIdx = qIndices[i];
        let limit = qLimit[qIdx];
        let x = qX[qIdx];

        // While there are nodes that meet the budget limit, add their depths to the SegTree
        while (nodePtr < N && pref[nodes[nodePtr]] <= limit) {
            let u = nodes[nodePtr];
            updateTree(tin[u], depth[u]);
            nodePtr++;
        }

        // Check the maximum depth found in the subtree range [tin[x] to tout[x]]
        let maxD = queryMax(tin[x], tout[x]);

        if (maxD >= depth[x]) {
            ans[qIdx] = maxD - depth[x] + 1;
        } else {
            ans[qIdx] = 0;
        }
    }

    // Efficiently output all answers
    console.log(ans.join('\n'));
}

